    for _ in range(t):
        n, m = int(input_data[idx]), int(input_data[idx+1]); idx+=2
        grid = []
        lab = None
        for i in range(n):
            row = input_data[idx].decode(); idx+=1
            grid.append(list(row))
            for j, c in enumerate(row):
                if c == 'L':
                    lab = (i, j)

        dirs = [(-1,0),(1,0),(0,-1),(0,1)]
        # count of non-forceable free neighbors
        non_force = [[0]*m for _ in range(n)]
        for i in range(n):
            for j in range(m):
                if grid[i][j] != '#':
                    cnt = 0
                    for dr,dc in dirs:
                        ni,nj = i+dr,j+dc
                        if 0<=ni<n and 0<=nj<m and grid[ni][nj]!='#':
                            cnt+=1
                    non_force[i][j] = cnt

        forceable = [[False]*m for _ in range(n)]
        q = deque()
        li, lj = lab
        forceable[li][lj] = True
        q.append((li,lj))

        while q:
            r,c = q.popleft()
            for dr,dc in dirs:
                nr,nc = r+dr,c+dc
                if 0<=nr<n and 0<=nc<m and grid[nr][nc]!='#' and not forceable[nr][nc]:
